--
-- Table structure for table `deliveries`
--

DROP TABLE IF EXISTS `deliveries`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `deliveries` (
  `Delivery_ID` int NOT NULL AUTO_INCREMENT,
  `Order_ID` int NOT NULL,
  `Vehicle_ID` int NOT NULL,
  `Estimated_Time` datetime DEFAULT NULL,
  `Delivery_Status` enum('In Transit','Completed','Failed') DEFAULT 'In Transit',
  `Driver_Note` varchar(255) NOT NULL,
  PRIMARY KEY (`Delivery_ID`),
  UNIQUE KEY `Order_ID` (`Order_ID`),
  KEY `Vehicle_ID` (`Vehicle_ID`),
  KEY `idx_deliveries_status` (`Delivery_Status`),
  CONSTRAINT `deliveries_ibfk_1` FOREIGN KEY (`Order_ID`) REFERENCES `orders` (`Order_ID`) ON DELETE CASCADE,
  CONSTRAINT `deliveries_ibfk_2` FOREIGN KEY (`Vehicle_ID`) REFERENCES `vehicles` (`Vehicle_ID`) ON DELETE CASCADE,
  CONSTRAINT `chk_driver_note` CHECK ((`Driver_Note` in (_utf8mb4'Handle with care',_utf8mb4'Gate code 1234',_utf8mb4'Call before arrival')))
) ENGINE=InnoDB AUTO_INCREMENT=511 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

