/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trg_update_order_on_delivery` AFTER UPDATE ON `deliveries` FOR EACH ROW BEGIN
    IF NEW.Delivery_Status = 'Completed' THEN
        UPDATE Orders SET Status = 'Delivered'
        WHERE Order_ID = NEW.Order_ID;
    END IF;
END */;;
